import re

with open('./llvm/lib/Transforms/Scalar/GVN.cpp', 'r') as f:
    content = f.read()

# Find the section we need to fix
# Look for the void type check pattern
pattern = r'(\s*// Instructions with void type don\'t return a value, so there\'s\n\s*// no point in trying to find redundancies in them\.\n\s*if \(I->getType\(\)->isVoidTy\(\)\)\n\s*return false;\n\n\s*uint32_t NextNum = VN\.getNextUnusedValueNumber\(\);\n\s*unsigned Num = VN\.lookupOrAdd\(I\);\n\n\s*// Allocations are always uniquely numbered, so we can save time and memory\n\s*// by fast failing them\.\n\s*if \(isa<AllocaInst>\(I\) \|\| I->isTerminator\(\) \|\| isa<PHINode>\(I\)\) \{\n\s*LeaderTable\.insert\(Num, I, I->getParent\(\)\);\n\s*return false;\n\s*\})'

match = re.search(pattern, content, re.DOTALL)
if match:
    # Replace with fixed version including token/metadata check
    fixed = '''  // Instructions with void type don't return a value, so there's
  // no point in trying to find redundancies in them.
  if (I->getType()->isVoidTy())
    return false;

  // Token-like and metadata types cannot be used in PHI nodes, so skip them.
  if (I->getType()->isTokenLikeTy() || I->getType()->isMetadataTy())
    return false;

  uint32_t NextNum = VN.getNextUnusedValueNumber();
  unsigned Num = VN.lookupOrAdd(I);

  // Allocations are always uniquely numbered, so we can save time and memory
  // by fast failing them.
  if (isa<AllocaInst>(I) || I->isTerminator() || isa<PHINode>(I)) {
    LeaderTable.insert(Num, I, I->getParent());
    return false;
  }'''

    content = content[:match.start()] + fixed + content[match.end():]

    with open('./llvm/lib/Transforms/Scalar/GVN.cpp', 'w') as f:
        f.write(content)
    print("Fixed GVN.cpp")
else:
    print("Pattern not found, trying alternative approach")
EOF
python3 /tmp/fix_gvn.py
```

